import React, { useState, useEffect, useCallback } from 'react';
import { Link } from 'react-router-dom';
import Navbar from '../components/Navbar';
import Sidebar from '../components/Sidebar';
import ProgressChart from '../components/ProgressChart';
import DailyTaskCard from '../components/DailyTaskCard';
import MissionTracker from '../components/MissionTracker';
import { useAuth } from '../context/AuthContext';
import { dashboardAPI } from '../services/api';

/* ── Stat Card ─────────────────────────────────────────────── */
function StatCard({ icon, label, value, sub, color }) {
    return (
        <div className="stat-card">
            <div className={`w-10 h-10 rounded-xl flex items-center justify-center text-xl mb-1 ${color}`}>
                {icon}
            </div>
            <p className="text-white/50 text-xs">{label}</p>
            <p className="text-white text-2xl font-bold leading-none">{value}</p>
            {sub && <p className="text-white/30 text-xs mt-0.5">{sub}</p>}
        </div>
    );
}

/* ── Quick action button ──────────────────────────────────── */
function QuickAction({ to, icon, label, color }) {
    return (
        <Link
            to={to}
            className="glass-card p-4 flex flex-col items-center gap-2 text-center
                 hover:scale-105 transition-transform duration-200 group"
        >
            <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-2xl ${color}
                       group-hover:shadow-neon-blue transition-all`}>
                {icon}
            </div>
            <span className="text-white/70 text-xs font-medium group-hover:text-white transition-colors">
                {label}
            </span>
        </Link>
    );
}

export default function Dashboard() {
    const { user, updateUser } = useAuth();
    const [sidebarOpen, setSidebarOpen] = useState(false);
    const [stats, setStats] = useState(null);
    const [tasks, setTasks] = useState([]);
    const [progress, setProgress] = useState(null);
    const [loading, setLoading] = useState(true);

    const fetchData = useCallback(async () => {
        try {
            const [statsRes, tasksRes, progressRes] = await Promise.allSettled([
                dashboardAPI.getStats(),
                dashboardAPI.getDailyTasks(),
                dashboardAPI.getProgress(),
            ]);
            if (statsRes.status === 'fulfilled') setStats(statsRes.value.data);
            if (tasksRes.status === 'fulfilled') setTasks(tasksRes.value.data?.tasks || []);
            if (progressRes.status === 'fulfilled') setProgress(progressRes.value.data);
        } catch {
            /* Use demo data silently */
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => { fetchData(); }, [fetchData]);

    const handleCompleteTask = async (taskId) => {
        try {
            const res = await dashboardAPI.completeTask(taskId);
            if (res.data?.xpEarned) {
                updateUser({ xp: (user?.xp || 0) + res.data.xpEarned });
            }
        } catch { /* ignore */ }
    };

    /* ── Demo stats if backend unavailable ─────────────────── */
    const displayStats = stats || {
        xp: user?.xp || 1250,
        level: user?.level || 3,
        rating: user?.rating || 78,
        sessions: 24,
        streak: 7,
        rank: '#42',
    };

    const xpToNext = 1000 - (displayStats.xp % 1000);
    const xpPercent = ((displayStats.xp % 1000) / 1000) * 100;

    const greetingHour = new Date().getHours();
    const greeting = greetingHour < 12 ? 'Good morning' : greetingHour < 18 ? 'Good afternoon' : 'Good evening';

    return (
        <div className="min-h-screen bg-dark-900 flex">
            <Sidebar open={sidebarOpen} onClose={() => setSidebarOpen(false)} />

            <div className="flex-1 flex flex-col min-w-0">
                <Navbar onMenuClick={() => setSidebarOpen(true)} />

                <main className="flex-1 p-4 md:p-6 space-y-6 overflow-y-auto">
                    {/* Greeting banner */}
                    <div className="relative glass-card p-6 overflow-hidden">
                        <div className="absolute inset-0 bg-hero-glow pointer-events-none" />
                        <div className="relative z-10 flex items-center justify-between">
                            <div>
                                <p className="text-white/50 text-sm">{greeting},</p>
                                <h2 className="font-display font-bold text-2xl text-white mt-0.5">
                                    {user?.name?.split(' ')[0] || 'Champion'} 👋
                                </h2>
                                <p className="text-white/40 text-sm mt-1">
                                    Ready to level up your communication today?
                                </p>

                                {/* XP progress */}
                                <div className="mt-4 max-w-xs">
                                    <div className="flex justify-between text-xs mb-1.5">
                                        <span className="text-white/50">Level {displayStats.level}</span>
                                        <span className="text-neon-yellow font-semibold">{displayStats.xp} XP</span>
                                    </div>
                                    <div className="progress-bar">
                                        <div className="progress-fill" style={{ width: `${xpPercent}%` }} />
                                    </div>
                                    <p className="text-white/30 text-xs mt-1">{xpToNext} XP to Level {displayStats.level + 1}</p>
                                </div>
                            </div>

                            <div className="hidden sm:flex flex-col items-center gap-1 flex-shrink-0">
                                <div className="w-20 h-20 rounded-2xl bg-gradient-to-br from-neon-yellow/20 to-neon-pink/20
                                border border-neon-yellow/30 flex flex-col items-center justify-center">
                                    <span className="text-neon-yellow text-2xl font-bold">{displayStats.streak}</span>
                                    <span className="text-white/40 text-[10px]">day streak</span>
                                </div>
                                <span className="text-neon-yellow text-xs">🔥 On fire!</span>
                            </div>
                        </div>
                    </div>

                    {/* Stat cards */}
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                        <StatCard icon="⭐" label="Rating Score" value={displayStats.rating} sub="out of 100" color="bg-neon-yellow/20" />
                        <StatCard icon="🎯" label="Sessions Done" value={displayStats.sessions} sub="all time" color="bg-primary-500/20" />
                        <StatCard icon="🏆" label="Global Rank" value={displayStats.rank} sub="leaderboard" color="bg-neon-green/20" />
                        <StatCard icon="🔥" label="Day Streak" value={`${displayStats.streak}d`} sub="keep going!" color="bg-neon-pink/20" />
                    </div>

                    {/* Quick actions */}
                    <div>
                        <h3 className="section-title mb-3">Jump Back In</h3>
                        <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-6 gap-3">
                            <QuickAction to="/practice" icon="🎤" label="Practice Speech" color="bg-primary-500/20" />
                            <QuickAction to="/interview" icon="💼" label="Mock Interview" color="bg-neon-yellow/20" />
                            <QuickAction to="/gd" icon="👥" label="Group Discussion" color="bg-neon-green/20" />
                            <QuickAction to="/learning" icon="📚" label="Learning Hub" color="bg-accent-500/20" />
                            <QuickAction to="/challenges" icon="⚡" label="Challenges" color="bg-neon-pink/20" />
                            <QuickAction to="/personality" icon="🧠" label="Personality" color="bg-primary-600/20" />
                        </div>
                    </div>

                    {/* Chart + Tasks + Missions */}
                    <div className="grid grid-cols-1 lg:grid-cols-5 gap-6">
                        <div className="lg:col-span-3 space-y-5">
                            <ProgressChart data={progress?.weekly} loading={loading} />
                            <MissionTracker />
                        </div>
                        <div className="lg:col-span-2">
                            <DailyTaskCard tasks={tasks} onComplete={handleCompleteTask} loading={loading} />
                        </div>
                    </div>
                </main>
            </div>
        </div>
    );
}
